class Playground {
    async run(inputs) {
        const candidates = inputs[0].split(',').map(n => parseInt(n.trim())).sort((a, b) => a - b);
        const target = parseInt(inputs[1]);

        // Initialize slots
        await this.candidates_arr.init(candidates);
        await this.current_path.init([]);
        await this.results.init([]);
        await this.vars.init([["Target", target]]);
        await this.callstack.init();
        await this.recursion_tree.init();

        const finalResults = [];
        let nodeIdCounter = 0;

        const backtrack = async (remaining, startIdx, parentId) => {
            const nodeId = `node-${nodeIdCounter++}`;
            const label = `Rem: ${remaining}`;

            // Visualization: Enter Node and Push Frame
            await this.callstack.pushFrame("backtrack", { remaining, startIdx });
            await this.recursion_tree.enterNode(nodeId, label);
            await this.vars.put("Current Remaining", remaining);
            await this.vars.put("Start Index", startIdx);

            this.log(`Exploring combinations with remaining sum: ${remaining}`);
            await this.await();

            // Base Case: Target reached
            if (remaining === 0) {
                const validCombo = [...this.current_path.getValues()];
                finalResults.push(validCombo);
                await this.results.push(`[${validCombo.join(',')}]`);
                this.log("✅ Target reached! Adding to results.");
                await this.await();

                await this.recursion_tree.exitNode("#00f5a0"); // Success color
                await this.callstack.popFrame(true);
                return;
            }

            // Base Case: Target exceeded
            if (remaining < 0) {
                this.log("❌ Sum exceeded target. Backtracking...");
                await this.await();
                await this.recursion_tree.exitNode("#ff4d4d"); // Failure color
                await this.callstack.popFrame(false);
                return;
            }

            for (let i = startIdx; i < candidates.length; i++) {
                const val = candidates[i];

                // Optimization: If current candidate is greater than remaining, 
                // and candidates are sorted, no need to check further
                if (val > remaining) {
                    this.log(`${val} is greater than remaining ${remaining}. Skipping rest of candidates.`);
                    break;
                }

                // Process: Choose the number
                await this.candidates_arr.highlight(i, "#00e0ff");
                await this.current_path.push(val);
                this.log(`Choosing ${val}. Remaining becomes ${remaining - val}`);
                await this.await();

                // Recurse: Note we pass 'i' as startIdx because we can reuse the same element
                await backtrack(remaining - val, i, nodeId);

                // Backtrack: Remove the number
                await this.current_path.pop();
                await this.candidates_arr.highlight(i, null);
                this.log(`Backtracked: Removed ${val}`);
                await this.vars.put("Current Remaining", remaining); // Reset visual var context
                await this.await();
            }

            await this.recursion_tree.exitNode();
            await this.callstack.popFrame();
        };

        await backtrack(target, 0, null);

        this.log("Backtracking complete.");
        return finalResults;
    }
}
